/* barlow-fonts.js - registers Barlow (SIL OFL) into jsPDF via the addFonts event
   so each document embeds it. Load AFTER jspdf.umd.min.js. */
(function () {
  if (!window.jspdf || !window.jspdf.jsPDF) { console.warn('[BVA] jsPDF not loaded before barlow-fonts.js'); return; }
  var jsPDFAPI = window.jspdf.jsPDF.API;
  var REG = '';
  var BOLD = '';
  jsPDFAPI.events.push(['addFonts', function () {
    this.addFileToVFS('Barlow-Regular.ttf', REG);
    this.addFont('Barlow-Regular.ttf', 'Barlow', 'normal');
    this.addFileToVFS('Barlow-Bold.ttf', BOLD);
    this.addFont('Barlow-Bold.ttf', 'Barlow', 'bold');
  }]);
})();